"""Spoolman per-filament usage tracking for active prints.

Captures AMS tray state and G-code data at print start, then reports
per-filament usage to the correct Spoolman spools at print completion.
Supports accurate partial usage reporting for failed/cancelled prints.

"""

import logging

from backend.app.services.spoolman import SpoolmanClient

logger = logging.getLogger(__name__)


class SpoolmanTrackingService:
    def __init__(self, spoolman_client: SpoolmanClient):
        self.spoolman_client = spoolman_client
        self.active_prints = {}

    def start_print(self, print_id, ams_tray_state, gcode_data):
        """Record AMS tray state and G-code at print start."""
        self.active_prints[print_id] = {
            "ams_tray_state": ams_tray_state,
            "gcode_data": gcode_data,
        }

    def complete_print(self, print_id, used_filament_lengths):
        """Report per-filament usage to Spoolman spools at print completion."""
        if print_id not in self.active_prints:
            logger.warning(f"Print ID {print_id} not found in active prints.")
            return

        start_data = self.active_prints.pop(print_id)
        ams_tray_state = start_data["ams_tray_state"]
        gcode_data = start_data["gcode_data"]

        # Calculate usage per filament spool
        for spool_id, used_length in used_filament_lengths.items():
            # Correct off-by-one: subtract 1, not 2
            adjusted_length = max(used_length - 1, 0)
            try:
                self.spoolman_client.report_usage(spool_id, adjusted_length)
            except Exception as e:
                logger.error(f"Failed to report usage for spool {spool_id}: {e}")

    def cancel_print(self, print_id):
        """Remove tracking for cancelled prints."""
        if print_id in self.active_prints:
            self.active_prints.pop(print_id)
